```json
{
  "protocol": "fpsp/0.1",
  "kind": "first-person-spellbook",
  "is_personal_patch_of": "privacymage grimoire v10.4.0 (First Person Spellbook)",
  "title": "<your book's name>",
  "created": "2026-06-19",

  "first_person": {
    "name": "<your mouse-name>",
    "sigil": "<your emoji sigil>",
    "vertex": null,
    "proverb": "<your one true proverb>",
    "spell": "<that proverb's spell string, from the legend>"
  },

  "derived_from": {
    "canon": "privacymage grimoire (First Person Spellbook)",
    "version": "10.4.0",
    "relation": "I read this as a root. This version is mine. It does not edit the canon.",
    "hosted": [
      "https://agentprivacy.ai",
      "https://spellweb.ai",
      "https://soulbis.com"
    ],
    "ipfs_resolver": "https://sync.agentprivacy.ai/ipfs/<CID>",
    "repos": [
      "https://github.com/mitchuski/cityofmages",
      "https://github.com/mitchuski/star"
    ]
  },

  "legend": {
    "shared": "spell-emoji-legend (see ./reference/spell-emoji-legend.md or the hosted canon)",
    "additions": [
      { "symbol": "", "meaning": "", "why": "a symbol I needed that the shared legend did not carry" }
    ]
  },

  "acts": [
    { "act": 1, "title": "Venice, 1494", "my_line": "<one line: what this act means to me>" },
    { "act": 4, "title": "The Blade Alone (MyTerms)", "my_line": "<my first blade / default refusal>" },
    { "act": 6, "title": "Trust Graph Plane (Trust over IP)", "my_line": "<who is in my trust graph>" },
    { "act": 21, "title": "The Hitchhiker's Gambit", "my_line": "<where I recognised my Swordsman>" },
    { "act": 31, "title": "The First Delegation", "my_line": "<my first irreversible delegation>" }
  ],
  "acts_note": "One line per act, distilled from narrative/acts.md. Include all 31 if you can; the five seeded above are the load-bearing ones.",

  "proverbs": [
    {
      "id": "p1",
      "title": "",
      "proverb": "",
      "poem": null,
      "spell": "",
      "glyph_ref": "",
      "polarity": "0 + / 0 -",
      "canon_act": null,
      "source_truth": "the raw sentence from my Step-2 conversation"
    }
  ],

  "local_context": {
    "note": "The Context Bridge — where the narrative touches MY own work and machine. PRIVATE by default (the Swordsman's domain): this maps your real filesystem. Keep it local; strip or redact paths before pinning publicly. Fill via templates/context-bridge.template.md → your-folder/context-bridge.md.",
    "private": true,
    "include_when_pinning": false,
    "bridges": [
      { "act_or_theme": "", "path": "", "what": "my own work this connects to", "why": "the resonance with the act/proverb", "proverb_ref": "", "share": false }
    ]
  },

  "rehydration": {
    "note": "How any agent — yours or another's — reconstitutes this book's understanding.",
    "instructions": "Load the shared legend and the canon (from derived_from.hosted). For each proverb, read its spell with the legend and its glyph for tone, then restate, in this first person's voice, the understanding it compresses. Preserve legend.additions and any divergence from the canon — do not flatten to it. When local_context is present AND the reader is the owner's own agent, connect a proverb to the real local work it concerns (local_context.bridges[].path); never surface those paths to anyone but the owner.",
    "prompt": "You are reconstituting a first person's spellbook under protocol fpsp/0.1. Given the shared spell-emoji legend and the privacymage canon, expand each proverb from its compressed spell + glyph into the fuller understanding it stands for, speaking as this first person (<name> <sigil>). Honour their legend additions. Do not collapse their voice into the canon's. If you are the owner's own agent and local_context is present, ground each relevant proverb in the owner's actual work (their local paths); keep those private."
  },

  "signature": "(<your sigil> ⊥ ⿻ ⊥ <complement>)😊",

  "pinning": {
    "status": "unpinned",
    "intent": "I pin this myself, when I am ready. The facilitator does not pin it for me.",
    "pin_cid": null,
    "pinned_at": null,
    "how": "Pin this JSON to IPFS (or your own store) and record the CID + date here. Your book becomes content-addressed and shareable without anyone's local machine."
  }
}
```

